command:
curl -s -o /dev/null -w "TTFB: %{time_starttransfer}s\nTotal: %{time_total}s\nSize: %{size_download} bytes\n" http://localhost:4201/api/sources -H "Authorization: Bearer $(docker compose exec -T web node -e "
const { createSigner } = require('fast-jwt');
const sign = createSigner({ key: process.env.NEXTAUTH_SECRET });
console.log(sign({ sub: 'test', email: 'test' }));
" 2>/dev/null)" 2>&1

TOKEN=$(docker compose exec -T api node -e "
const { createSigner } = require('fast-jwt');
const sign = createSigner({ key: process.env.NEXTAUTH_SECRET });
process.stdout.write(sign({ sub: 'cmmnxixf40000o001x0gn1ve1', email: 'mail@ch-becker.de' }));
" 2>/dev/null) && curl -s -o /dev/null -w "TTFB: %{time_starttransfer}s\nTotal: %{time_total}s\nSize: %{size_download} bytes\n" "http://localhost:4201/api/sources" -H "Authorization: Bearer $TOKEN"

mkdir -p prisma/migrations/1_per_event_type_config && cat > prisma/migrations/1_per_event_type_config/migration.sql << 'SQLEOF'
-- AlterTable: Add bookingCalendarEntryId to event_types
ALTER TABLE "event_types" ADD COLUMN "bookingCalendarEntryId" TEXT;

-- AlterTable: Add eventTypeId to availability_rules
ALTER TABLE "availability_rules" ADD COLUMN "eventTypeId" TEXT;

-- Drop old unique constraint
ALTER TABLE "availability_rules" DROP CONSTRAINT IF EXISTS "availability_rules_userId_dayOfWeek_key";

-- Create new unique constraint (nullable eventTypeId handled by Prisma)
CREATE UNIQUE INDEX "availability_rules_userId_eventTypeId_dayOfWeek_key" ON "availability_rules"("userId", "eventTypeId", "dayOfWeek");

-- AddForeignKey
ALTER TABLE "availability_rules" ADD CONSTRAINT "availability_rules_eventTypeId_fkey" FOREIGN KEY ("eventTypeId") REFERENCES "event_types"("id") ON DELETE CASCADE ON UPDATE CASCADE;
SQLEOF
echo "OK"
